import { MemoryChunk } from './types'

export class MarkdownChunker {
  private cache: Map<string, MemoryChunk[]>

  constructor(private config: SearchConfig) {
    this.cache = new Map()
  }

  async createChunks(content: string, file: string): Promise<MemoryChunk[]> {
    const chunks = new Set<MemoryChunk>()
    const headings = this.extractHeadings(content)

    let currentChunk: string = ''
    let currentLocation = this.getLocation(file, 0)
    let currentHeading = headings[0]

    const chunkContent = []

    for (const [line, heading] of headings) {
      chunkContent.push({ line, heading })

      if (chunkContent.length >= this.config.chunkSize) {
        const chunkText = chunkContent.map((c) => c.line.slice(0, 100)).join('\n')
        chunks.add({
          id: file + ':' + line,
          content: chunkText,
          location: currentLocation,
          metadata: {
            file,
            line,
            title: currentHeading,
            headings: chunkContent.map((c) => c.heading)
          }
        })
        chunkContent.splice(0, this.config.chunkSize)
      }

      if (this.getConfigOverHeadings(file, line)) {
        currentChunk = ''
        currentLocation = this.getLocation(file, line)
        currentHeading = headings[line]
      }
    }

    const lastChunk = chunkContent.length > 0 ?
      {
        id: file + ':last',
        content: chunkContent.map((c) => c.line.slice(0, 100)).join('\n'),
        location: currentLocation,
        metadata: {
          file,
          line: currentLocation.line,
          title: currentHeading,
          headings: chunkContent.map((c) => c.heading)
        }
      } : null

    return [...chunks, lastChunk].sort((a, b) => a.id.localeCompare(b.id))
  }

  getChunkedContent(content: string): string[] {
    return content.split(/\n/).map((line, index) => index)
  }
}
