// pipeline.ts

import { MemorySearchConfig } from './types'
import { MiniSearch } from 'minisearch'
import { Embeddings } from '@xenova/transformers'
import { CrossEncoder } from '@xenova/transformers'

export class SearchPipeline {
  private miniSearch: MiniSearch
  private embeddings: Embeddings
  private crossEncoder: CrossEncoder

  constructor(private config: SearchConfig) {
    this.miniSearch = new MiniSearch({
      fields: ['content'],
      storeFields: ['file', 'line']
    })

    this.embeddings = null  // Will be lazy-loaded
    this.crossEncoder = null
  }

  async indexFiles(filePaths: string[]): Promise<void> {
    for (const filePath of filePaths) {
      const file = await fs.readFile(filePath, 'utf-8')
      const chunks = await this.chunker.createChunks(file, filePath)

      for (const chunk of chunks) {
        this.miniSearch.add({
          id: chunk.id,
          content: chunk.content,
          metadata: { file: chunk.metadata.file, line: chunk.metadata.line }
        })
      }
    }
  }

  async search(query: string, k: number): Promise<SearchResult[]> {
    const startTime = Date.now()

    // BM25 Search
    const bm25Results = this.miniSearch.search(query, { k })

    // Semantic Search
    const embeddings = await this.getEmbeddings(query)
    const embeddingsIndex = await this.getEmbeddingsEmbeddings()
    const semanticResults = embeddingsIndex.knn(embeddings, k).map((res) => ({
      id: res.indexId,
      score: res.score,
      metadata: res.metadata
    }))

    // Reranking
    const rerankResults = await this.reranker.rerank(query, [...bm25Results, ...semanticResults].slice(0, k))

    // Fusion
    const fusedResults = this.fuseResults(bm25Results, semanticResults, rerankResults)

    return fusedResults
  }

  private fuseResults(bm25: SearchResult[], semantic: SearchResult[], rerank: SearchResult[]): SearchResult[] {
    const combined = new Map<string, SearchResult>()

    for (const result of [...bm25, ...semantic, ...rerank]) {
      combined.set(result.id, {
        ...result,
        score: result.score
      })
    }

    return Array.from(combined.values()).sort((a, b) => b.score - a.score).slice(0, k)
  }

  private async getEmbeddings(query: string): Promise<number[]> {
    if (!this.embeddings) {
      this.embeddings = new Embeddings({ model: 'sentence-transformers/all-MiniLM-L6-v2' })
    }
    return this.embeddings.encode(query)
  }
}
