      k: Math.min(k, docCount / 2) // Avoid searching too heavily
    }) as any[]

    const resultsWithMetadata = results.map((res) => ({
      id: res.id,
      score: res.score * this.searchConfig.semanticThreshold,
      chunk: this.getChunkFromResult(res.id),
      metadata: {
        source: 'semantic',
        timestamp: Date.now(),
        searchQuery: query
      }
    }))

    const searchTime = Date.now() - startTime
    return {
      results: resultsWithMetadata,
      totalChunks: docCount,
      searchTime,
      query
    }
  }

  // Reranking
  private async rerank(query: string, candidates: SearchResult[]): Promise<SearchResult[]> {
    if (!this.crossEncoder) return candidates.slice(0, this.searchConfig.rerankTopK)

    try {
      const startTime = Date.now()

      // Get top candidates from all search methods
      const rankedResults = await this.crossEncoder.computeSimilarity(
        query,
        candidates.map(c => c.content)
      )

      const rankedCandidates = candidates.map((candidate, index) => ({
        ...candidate,
        score: rankedResults[index],
        metadata: {
          ...candidate.metadata,
          source: 'rerank'
        }
      }))

      return rankedCandidates
        .filter((r) => r.score > this.searchConfig.bm25Threshold)
        .sort((a, b) => b.score - a.score)
        .slice(0, this.searchConfig.rerankTopK)
        .map((r) => ({
          ...r,
          score: this.searchConfig.rerankTopK > 0 ? r.score : 1
        }))

      const searchTime = Date.now() - startTime
      return {
        results,
        totalChunks: candidates.length,
        searchTime,
        query
      }
    } catch (e) {
      console.error('Reranking failed:', e)
      return candidates.slice(0, this.searchConfig.rerankTopK)
    }
  }

  // Fusion Results
  private fuseResults(
    bm25Results: SearchResult[], 
    semanticResults: SearchResult[], 
    rerankResults: SearchResult[]
  ): SearchResult[] {
    // Combine all results with deduplication by chunk id
    const combinedMap = new Map<string, SearchResult>()
    const dedupMap = new Map<string, { count: number; sources: Set<string> }>()

    const addResult = (result: SearchResult, source: 'bm25' | 'semantic' | 'rerank') => {
      const dedupKey = result.chunk.id
      if (!dedupMap.has(dedupKey)) {
        dedupMap.set(dedupKey, { count: 0, sources: new Set() })
      }

      dedupMap.get(dedupKey)!.count++
      dedupMap.get(dedupKey)!.sources.add(source)

      combinedMap.set(dedupKey, result)
    }

    bm25Results.forEach(r => addResult(r, 'bm25'))
    semanticResults.forEach(r => addResult(r, 'semantic'))
    rerankResults.forEach(r => addResult(r, 'rerank'))

    // Sort by score and metadata sources
    const results = Array.from(combinedMap.entries())
      .map(([id, result]) => ({
        ...result,
        metadata: {
          ...result.metadata,
          bm25Score: bm25Results.find(b => b.id === id) ? 1 : 0,
          semanticScore: semanticResults.find(s => s.id === id) ? 1 : 0,
          rerankScore: rerankResults.find(r => r.id === id) ? 1 : 0
        }
      }))
      .sort((a, b) => {
        // First by rerank score, then by bm25, then by semantic
        return (
          (b.metadata.rerankScore && !a.metadata.rerankScore) ? -1 :
          (a.metadata.rerankScore && !b.metadata.rerankScore) ? 1 :
          (b.metadata.bm25Score && !a.metadata.bm25Score) ? -1 :
          (a.metadata.bm25Score && !b.metadata.bm25Score) ? 1 :
          (b.metadata.semanticScore && !a.metadata.semanticScore) ? -1 :
          (a.metadata.semanticScore && !b.metadata.semanticScore) ? 1 :
          0
        )
      })
      .slice(0, this.searchConfig.returnTop)

    return results
  }

  // Execute full search pipeline
  async search(query: string): Promise<SearchResult[]> {
    try {
      console.log(`[${new Date().toISOString()}] Searching for: "${query}"`)

      // BM25 search
      const bm25Results = await this.bm25Search(query, this.searchConfig.bm25TopK)

      // Semantic search
      const semanticResults = await this.semanticSearch(query, this.searchConfig.semanticK)

      // Rerank
      const rerankResults = await this.rerank(query, [...bm25Results, ...semanticResults])

      // Fuse results
      const fusedResults = this.fuseResults(bm25Results, semanticResults, rerankResults)

      return this.cleanupResults(fusedResults)
    } catch (e) {
      console.error('Search failed:', e)
      return []
    }
  }

  // Cleanup results - remove excessive fields
  private cleanupResults(results: SearchResult[]): SearchResult[] {
    return results.map((r) => ({
      id: r.id,
      score: r.score,
      content: r.content,
      metadata: {
        ...r.metadata,
        file: r.metadata.file || null,
        line: r.metadata.line || 0
      }
    }))
  }

  // Get chunk from search result
  private getChunkFromResult(chunkId: string): MemoryChunk {
    // This would retrieve from the chunks store
    // Simplified for now
    return {
      id: chunkId,
      content: '',
      metadata: {}
    }
  }
}
